// // This module implements a 16-bit SRAM cell with read and write capabilities.
// It has the following ports:
// - clk: Clock signal
// - we: Write disable signal (1 for read, 0 for write)
// - addr: 4-bit address for selecting one of the 16 memory cells
// - data_in: 16-bit input data for writing
// - data_out: 16-bit output data for reading
// The SRAM should store the data written to it and return the stored data when read.
module sram_16bit (
    input clk,
    input we,
    input [3:0] addr,
    input [15:0] data_in,
    output reg [15:0] data_out
);
    reg [15:0] memory [0:15]; // 16 memory cells of 16 bits each

    always @(posedge clk) begin
        if (we) begin
            memory[addr] <= data_in; // Write data to memory
        end else begin
            data_out <= memory[addr]; // Read data from memory
        end
    end
endmodule

